def reverse(s): return s[::-1]
def is_palindrome(s): return s == s[::-1]
def count_vowels(s): return sum(1 for c in s.lower() if c in 'aeiou')

hard.solution:
def compose(*funcs):
    def composed(arg):
        result = arg
        for func in reversed(funcs):
            result = func(result)
        return result
    return composed

